issues.body:
### Steps to reproduce

1. Create a new Flutter project.
2. Add a FocusableActionDetector in a widget.
3. Configure specific keyboard actions within the FocusableActionDetector.
4. Run the application on Linux and Windows.
5. Observe that the keyboard actions work on Windows but not on Linux.

### Expected results

The keyboard actions configured in the FocusableActionDetector should work consistently across all platforms, including Linux.

### Actual results

On Linux, the keyboard actions within the FocusableActionDetector are not being triggered, while they work as expected on Windows.

### Code sample

<details open><summary>Code sample</summary>

```dart
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
        useMaterial3: true,
      ),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key, required this.title});

  final String title;

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  int _counter = 0;

  void _incrementCounter() {
    setState(() {
      _counter++;
    });
  }

  void _decrementCounter() {
    setState(() {
      _counter--;
    });
  }

  void keyboardActions(EventShortcutsIntent intent) async {
    switch (intent.type) {
      case EEventType.increment:
        _incrementCounter();
        break;
      case EEventType.decrement:
        _decrementCounter();
        break;
    }
  }

  @override
  Widget build(BuildContext context) {
    return FocusableActionDetector(
      shortcuts: getEventShortcuts(),
      actions: <Type, Action<EventShortcutsIntent>>{
        EventShortcutsIntent: CallbackAction<EventShortcutsIntent>(
          onInvoke: keyboardActions,
        ),
      },
      autofocus: true,
      descendantsAreFocusable: true,
      child: Scaffold(
        appBar: AppBar(
          backgroundColor: Theme
              .of(context)
              .colorScheme
              .inversePrimary,
          title: Text(widget.title),
        ),
        body: Center(
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: <Widget>[
              const Text(
                'You have pushed the button this many times:',
              ),
              Text(
                '$_counter',
                style: Theme
                    .of(context)
                    .textTheme
                    .headlineMedium,
              ),
            ],
          ),
        ),
        floatingActionButton: FloatingActionButton(
          onPressed: _incrementCounter,
          tooltip: 'Increment',
          child: const Icon(Icons.add),
        ),
      ),
    );
  }
}



Map<LogicalKeySet, Intent> getEventShortcuts() {
  return <LogicalKeySet, Intent>{
    LogicalKeySet(LogicalKeyboardKey.control, LogicalKeyboardKey.keyA): const EventShortcutsIntent.increment(),
    LogicalKeySet(LogicalKeyboardKey.control, LogicalKeyboardKey.keyB): const EventShortcutsIntent.decrement(),
  };
}

enum EEventType {
  increment, decrement;
}

class EventShortcutsIntent extends Intent {
  final EEventType type;

  const EventShortcutsIntent({required this.type});

  const EventShortcutsIntent.increment() : type = EEventType.increment;
  const EventShortcutsIntent.decrement() : type = EEventType.decrement;
}
```

</details>


